struct BinaryValidator {
    data: *const u8,
    size: usize,
}

impl BinaryValidator {
    fn new(data: *const u8, size: usize) -> Self {
        BinaryValidator { data, size }
    }

    fn validate(&self) -> bool {
        if self.data.is_null() || self.size == 0 {
            return false;
        }
        let ptr = unsafe { std::slice::from_raw_parts(self.data, self.size) };
        if ptr[0] == 0x7f && self.size >= 32 {
            true
        } else {
            false
        }
    }
}

