use std::fs;
use std::path::{Path, PathBuf};
use std::time::SystemTime;

struct BuildState {
    last_run: SystemTime,
}

fn get_current_state() -> Result<BuildState, std::io::Error> {
    Ok(BuildState {
        last_run: SystemTime::now(),
    })
}

fn check_file_timestamps(root_dir: &Path) -> Result<Vec<String>, std::io::Error> {
    let mut changed_files = Vec::new();
    if !root_dir.exists() {
        return Ok(changed_files);
    }

    for entry in fs::read_dir(root_dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_file() {
            let metadata = fs::metadata(&path)?;
            let modified = metadata.modified()?;
            changed_files.push(format!("{}:{}", path.display(), modified.duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs()));
        }
    }
    Ok(changed_files)
}

fn main() -> Result<(), std::io::Error> {
    let build_root = Path::new("src");
    if !build_root.exists() {
        println!("Build root not found.");
        return Ok(());
    }

    let changed = check_file_timestamps(build_root)?;

    if changed.is_empty() {
        println!("No files detected or all seem up to date.");
    } else {
        println!("Detected changes: {}", changed.len());
        for item in changed {
            print!(" - {}
", item);
        }
    }

    Ok(())
}
